// Clips de audio de relleno ("mmm...", "a ver...") pre-generados con la API
// de TTS de OpenAI (voz "marin", igual que la voz por defecto de las
// llamadas) y convertidos a audio/pcmu (G.711 mu-law 8kHz mono, el mismo
// formato que usa Twilio Media Streams) -- ver script de generacion en el
// historial de este cambio si hace falta regenerarlos o agregar mas.
//
// Se reproducen en cuanto el usuario termina de hablar (evento
// input_audio_buffer.speech_stopped) MIENTRAS OpenAI todavia esta generando
// la respuesta real -- no despues. Asi se elimina el silencio muerto entre
// turnos sin depender de la latencia del modelo (ver twilioMediaStreamHandler.js).
// Genericos por idioma (no por voz/acento de campana): timbre "marin" fijo,
// aceptado como simplificacion del MVP.

const ES_FILLERS = [
  // "mmm..."
  "",
  // "a ver..."
  "",
  // "eh..."
  "",
];

const EN_FILLERS = [
  // "um..."
  "",
  // "let's see..."
  "",
  // "so..."
  "",
];


const FILLERS_BY_LANGUAGE = { es: ES_FILLERS, en: EN_FILLERS };

function getRandomFiller(language) {
  const list = FILLERS_BY_LANGUAGE[language] || FILLERS_BY_LANGUAGE.es;
  const base64 = list[Math.floor(Math.random() * list.length)];
  return Buffer.from(base64, 'base64');
}

module.exports = { getRandomFiller };
